// Obtener datos del webhook original
const webhookData = $('Webhook Evolution API').first().json;
const messageType = webhookData.body.data.messageType;

let userMessage = '';
let phoneNumber = webhookData.body.data.key.remoteJid.replace('@s.whatsapp.net', '');
let pushName = webhookData.body.data.pushName || 'Usuario';

// Determinar el mensaje según el tipo
if (messageType === 'conversation') {
  userMessage = webhookData.body.data.message.conversation;
} else if (messageType === 'extendedTextMessage') {
  userMessage = webhookData.body.data.message.extendedTextMessage.text;
} else if (messageType === 'audioMessage') {
  // Si viene de transcripción
  try {
    const transcription = $('Transcribir con Whisper').first();
    userMessage = transcription.json.text || '[Audio no transcrito]';
  } catch (e) {
    userMessage = '[Error al transcribir audio]';
  }
}

return [{
  json: {
    chatInput: userMessage,
    sessionId: phoneNumber,
    phoneNumber: phoneNumber,
    pushName: pushName,
    instanceName: webhookData.body.instance,
    messageType: messageType,
    timestamp: new Date().toISOString()
  }
}];

